### Step 1: Define a Plugin Interface

First, define an interface that all plugins must adhere to. This interface will specify the methods that plugins must implement.

```python
from abc import ABC, abstractmethod

class PluginInterface(ABC):
    @abstractmethod
    def run(self, config: dict) -> None:
        pass

    @abstractmethod
    def get_name(self) -> str:
        pass

    @abstractmethod
    def get_version(self) -> str:
        pass
```

### Step 2: Create a Plugin Manager

Next, create a plugin manager that loads and manages plugins. This manager will handle loading plugins from a specified directory and executing them.

```python
import importlib
import os
from typing import List

class PluginManager:
    def __init__(self, plugin_dir: str):
        self.plugin_dir = plugin_dir
        self.plugins = []

    def load_plugins(self):
        if not os.path.exists(self.plugin_dir):
            return

        for filename in os.listdir(self.plugin_dir):
            if filename.endswith('.py'):
                module_name = os.path.splitext(filename)[0]
                module = importlib.import_module(f"{self.plugin_dir}.{module_name}")
                for _, cls in module.__dict__.items():
                    if isinstance(cls, type) and issubclass(cls, PluginInterface) and cls is not PluginInterface:
                        self.plugins.append(cls())

    def run_plugins(self, config: dict):
        for plugin in self.plugins:
            try:
                plugin.run(config)
            except Exception as e:
                logger.error(f"Plugin {plugin.get_name()} version {plugin.get_version()} failed: {e}")
```

