```python
import logging
from abc import ABC, abstractmethod

logger = logging.getLogger(__name__)

class PluginInterface(ABC):
    @abstractmethod
    def load(self):
        pass

    @abstractmethod
    def unload(self):
        pass

    @abstractmethod
    def run(self, *args, **kwargs):
        pass
```

#### 2. Plugin Registration Mechanism
Create a mechanism to register and discover plugins. This mechanism will also handle logging load times.

```python
import importlib
import os
import time
from typing import List

class PluginManager:
    def __init__(self, plugin_directory: str):
        self.plugins = {}
        self.plugin_directory = plugin_directory
        self.load_plugins()

    def load_plugins(self):
        start_time = time.time()
        for plugin_file in os.listdir(self.plugin_directory):
            if plugin_file.endswith('.py'):
                plugin_name = plugin_file[:-3]
                plugin_module = importlib.import_module(f"{self.plugin_directory}.{plugin_name}")
                for _, cls in plugin_module.__dict__.items():
                    if isinstance(cls, type) and issubclass(cls, PluginInterface) and cls is not PluginInterface:
                        plugin_instance = cls()
                        self.plugins[plugin_name] = plugin_instance
                        logger.info(f"Loaded plugin '{plugin_name}' in {time.time() - start_time:.2f} seconds")
                        start_time = time.time()

    def run_plugins(self, command: str, *args, **kwargs):
        for plugin in self.plugins.values():
            try:
                plugin.run(command, *args, **kwargs)
            except Exception as e:
                logger.error(f"Plugin '{plugin.__class__.__name__}' failed to run: {e}")
                logger.error(f"Error details: {e.__traceback__}")
```

